#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/wait.h>
#include <sys/types.h>

/* Maximum buffer size for messages */
#define BUFFER_SIZE 256

/* Compartment configuration structure */
typedef struct {
 char name[64];
 char privileges[5][32]; /* Array of allowed privileges */
 int num_privileges;
 int read_fd; /* Read end of pipe */
 int write_fd; /* Write end of pipe */
} Compartment;

/* Message structure for IPC */
typedef struct {
 char sender[64];
 char type[64];
 char data[BUFFER_SIZE];
 char allowed_recipients[5][32];
 int num_recipients;
} Message;

/* Function prototypes */
void init_compartment(Compartment *comp, const char *name, int *pipe_fds);
int check_privilege(Compartment *comp, const char *privilege);
int check_channel(Compartment *comp, const char *sender);
void send_message(int write_fd, Message *msg);
void receive_message(int read_fd, Message *msg);
void http_parser_process(int read_fd, int write_fd);
void cgi_engine_process(int read_fd, int write_fd);
void logger_process(int read_fd);

/* Initialize compartment with name and pipe */
void init_compartment(Compartment *comp, const char *name, int *pipe_fds) {
 strcpy(comp->name, name);
 comp->num_privileges = 0;
 comp->read_fd = pipe_fds[0];
 comp->write_fd = pipe_fds[1];
}

/* Check if compartment has specific privilege */
int check_privilege(Compartment *comp, const char *privilege) {
 for (int i = 0; i < comp->num_privileges; i++) {
 if (strcmp(comp->privileges[i], privilege) == 0) {
 return 1; /* Privilege granted */
 }
 }
 return 0; /* Privilege denied */
}

/* Check if sender is allowed to communicate with this compartment */
int check_channel(Compartment *comp, const char *sender) {
 /* For simplicity, allow communication from Compartment Manager */
 if (strcmp(sender, "Manager") == 0) {
 return 1;
 }
 return 0;
}

/* Send message through pipe */
void send_message(int write_fd, Message *msg) {
 write(write_fd, msg, sizeof(Message));
}

/* Receive message from pipe */
void receive_message(int read_fd, Message *msg) {
 read(read_fd, msg, sizeof(Message));
}

/* HTTP Parser Compartment Process */
void http_parser_process(int read_fd, int write_fd) {
 printf("[HTTP_Parser] Started (PID: %d)\n", getpid());

 /* Set privileges for HTTP Parser */
 char privileges[3][32] = {"read_socket", "parse_headers", "validate_request"};

 Message msg;
 while (1) {
 /* Wait for incoming messages */
 if (read(read_fd, &msg, sizeof(Message)) > 0) {
 printf("[HTTP_Parser] Received: type=%s, data=%s\n", msg.type, msg.data);

 /* Process HTTP request */
 if (strcmp(msg.type, "http_request") == 0) {
 printf("[HTTP_Parser] Parsing HTTP headers...\n");

 /* Create response for CGI Engine */
 Message response;
 strcpy(response.sender, "HTTP_Parser");
 strcpy(response.type, "execute_script");
 strcpy(response.data, "/cgi-bin/script.sh");
 strcpy(response.allowed_recipients[0], "CGI_Engine");
 response.num_recipients = 1;

 /* Send to CGI Engine (would use separate pipe in full implementation) */
 printf("[HTTP_Parser] Forwarding to CGI Engine\n");
 }
 }
 sleep(1);
 }
}

/* CGI Engine Compartment Process */
void cgi_engine_process(int read_fd, int write_fd) {
 printf("[CGI_Engine] Started (PID: %d)\n", getpid());

 /* Set privileges for CGI Engine - RESTRICTED! */
 char privileges[2][32] = {"execute_script", "limited_file_read"};

 Message msg;
 while (1) {
 if (read(read_fd, &msg, sizeof(Message)) > 0) {
 printf("[CGI_Engine] Received: type=%s, data=%s\n", msg.type, msg.data);

 /* Check privilege before executing */
 if (strcmp(msg.type, "execute_script") == 0) {
 printf("[CGI_Engine] EXECUTING script in sandbox: %s\n", msg.data);
 /* In real implementation: execute in sandboxed environment */
 }
 /* Try to access SSL operation - should be DENIED */
 else if (strcmp(msg.type, "encrypt") == 0) {
 printf("[CGI_Engine] DENIED: encrypt operation not in privileges!\n");
 printf("[CGI_Engine] Available privileges: execute_script, limited_file_read\n");
 }
 }
 sleep(1);
 }
}

/* Logger Compartment Process */
void logger_process(int read_fd) {
 printf("[Logger] Started (PID: %d)\n", getpid());

 /* Set privileges for Logger */
 char privileges[1][32] = {"append_log"};

 Message msg;
 while (1) {
 if (read(read_fd, &msg, sizeof(Message)) > 0) {
 printf("[Logger] Logging event from %s: %s - %s\n",
 msg.sender, msg.type, msg.data);
 }
 sleep(1);
 }
}

/* Demonstrate XOAR compartmentalization */
int main() {
 printf("========================================\n");
 printf("XOAR: Privilege Separation Demo (C)\n");
 printf("========================================\n\n");

 /* Create pipes for inter-compartment communication */
 int http_to_cgi[2];
 int to_logger[2];

 if (pipe(http_to_cgi) == -1 || pipe(to_logger) == -1) {
 perror("pipe failed");
 return 1;
 }

 printf("--- Creating Compartments (Processes) ---\n\n");

 /* Fork HTTP Parser Compartment */
 pid_t pid_http = fork();
 if (pid_http == 0) {
 close(http_to_cgi[0]); /* Close read end */
 http_parser_process(http_to_cgi[0], http_to_cgi[1]);
 exit(0);
 }

 /* Fork CGI Engine Compartment */
 pid_t pid_cgi = fork();
 if (pid_cgi == 0) {
 close(http_to_cgi[1]); /* Close write end */
 cgi_engine_process(http_to_cgi[0], to_logger[1]);
 exit(0);
 }

 /* Fork Logger Compartment */
 pid_t pid_logger = fork();
 if (pid_logger == 0) {
 close(to_logger[1]); /* Close write end */
 logger_process(to_logger[0]);
 exit(0);
 }

 /* Parent process - Compartment Manager */
 printf("[Manager] Created %d compartments\n", 3);
 printf("[Manager] HTTP_Parser PID: %d\n", pid_http);
 printf("[Manager] CGI_Engine PID: %d\n", pid_cgi);
 printf("[Manager] Logger PID: %d\n\n", pid_logger);

 sleep(1);

 /* Demonstrate inter-compartment communication */
 printf("--- Testing Inter-Compartment Communication ---\n\n");

 /* Send HTTP request to HTTP Parser */
 Message http_msg;
 strcpy(http_msg.sender, "Manager");
 strcpy(http_msg.type, "http_request");
 strcpy(http_msg.data, "GET /index.html HTTP/1.1");

 write(http_to_cgi[1], &http_msg, sizeof(Message));
 printf("[Manager] Sent HTTP request to HTTP_Parser\n");

 sleep(1);

 /* Send privilege violation attempt */
 Message encrypt_msg;
 strcpy(encrypt_msg.sender, "HTTP_Parser");
 strcpy(encrypt_msg.type, "encrypt");
 strcpy(encrypt_msg.data, "sensitive_data");

 write(http_to_cgi[1], &encrypt_msg, sizeof(Message));
 printf("[Manager] Sent encrypt attempt to CGI_Engine (should be DENIED)\n");

 sleep(1);

 /* Send log message */
 Message log_msg;
 strcpy(log_msg.sender, "HTTP_Parser");
 strcpy(log_msg.type, "log");
 strcpy(log_msg.data, "Request processed");

 write(to_logger[1], &log_msg, sizeof(Message));
 printf("[Manager] Sent log message to Logger\n");

 /* Wait for children */
 sleep(2);

 printf("\n--- Stopping Compartments ---\n");
 kill(pid_http, SIGTERM);
 kill(pid_cgi, SIGTERM);
 kill(pid_logger, SIGTERM);

 wait(NULL);
 wait(NULL);
 wait(NULL);

 printf("\nDemo completed. Each compartment runs with\n");
 printf("minimal privileges and isolated process space.\n");

 return 0;
}
